func TestRegression_ForwardCookiesFunctionBug(t *testing.T) {
	t.Run("ForwardCookies_Bug_Overwrites_Token_With_State", func(t *testing.T) {
		// Create an HTTP request with both state and token cookies
		httpReq := httptest.NewRequest(http.MethodPost, "http://localhost/auth/v1/callback", nil)

		// Add state cookie
